const item = items[0].json;

function getPath(obj, path) {
  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
}

// mesmo schema completo usado na extração da entrevista — inclui os
// campos "órfãos" que a Monique simplificada não coleta mais, além
// dos campos específicos de petição
const schemaCampos = {
  tipo_rescisao:      { label: "tipo de rescisão",                  path: "rescisao.tipo" },
  fgts_depositado:    { label: "se o FGTS foi depositado corretamente", path: "direitos.fgts_depositado" },
  ferias_vencidas:    { label: "férias vencidas",                    path: "direitos.ferias_terco" },
  trabalho_fds:       { label: "trabalho nos finais de semana",      path: "jornada.trabalho_fim_semana" },
  controle_ponto:     { label: "o controle de ponto",                path: "jornada.controle_ponto" },
  outros_direitos:    { label: "outras situações não conversadas",   path: "outros_direitos_mencionados" },
};

const schemaDocumentos = ["ctps", "trct", "extrato_fgts", "contracheque", "prova_agravante"];

const perguntas = {
  tipo_rescisao:        "Como foi o fim do seu contrato: demitido(a), pediu demissão, justa causa ou acordo?",
  fgts_depositado:      "O FGTS foi depositado corretamente durante todo o período?",
  ferias_vencidas:      "Na época da sua saída, você tinha férias vencidas — um período que já podia tirar mas não tirou?",
  assedio:              "Você sofreu algum tipo de assédio moral ou cobrança excessiva no trabalho?",
  desvio_funcao:        "Você trabalhava só na função registrada, ou também exercia outra função na prática?",
  detalhe_substituicao: "Você mencionou substituir a gerente/colega — quantas vezes isso aconteceu, e por quanto tempo cada vez?",
  trabalho_fds:         "Você trabalhava aos sábados, domingos ou feriados?",
  controle_ponto:       "Você assinava folha de ponto ou batia ponto?",
  outros_direitos:      "Teve alguma outra situação no trabalho que acha importante eu registrar?",
  jornada_detalhada:    "Qual era o seu horário de trabalho — entrada, intervalo e saída?",
  ctps:                 "Pode me enviar o PDF da sua Carteira de Trabalho Digital (CTPS)?",
  trct:                 "Pode me enviar o Termo de Rescisão (TRCT), se já tiver recebido?",
  extrato_fgts:         "Pode me enviar o Extrato do FGTS (app FGTS ou Caixa Tem)?",
  contracheque:         "Pode me enviar os contracheques dos últimos meses trabalhados?",
  prova_agravante:      "Você tem algum atestado, laudo ou print que comprove o que relatou?",
};

const dados = item.triagem || {};
const tiposRecebidos = new Set(item.tipos_documento_recebidos || []);

const pendentesKeys = [];

for (const [chave, info] of Object.entries(schemaCampos)) {
  const valor = getPath(dados, info.path);
  if (valor === undefined || valor === null || valor === "") {
    pendentesKeys.push(chave);
  }
}

const horarioReal = getPath(dados, "jornada.horario_real");
const intervalo = getPath(dados, "jornada.intervalo");
if (!horarioReal || !intervalo) {
  pendentesKeys.push("jornada_detalhada");
}

// 🆕 assédio: checa os dois lugares possíveis (bug de duplicação já
// identificado no prompt da Monique — direitos.assedio é o correto,
// mas agravantes.assedio pode ter sido gravado por engano em casos
// antigos, antes da correção do prompt)
const assedioDireitos = getPath(dados, "direitos.assedio");
const assedioAgravantes = getPath(dados, "agravantes.assedio");
if (assedioDireitos === undefined && assedioAgravantes === undefined) {
  pendentesKeys.push("assedio");
}

// 🆕 acúmulo/substituição de função: mesma lógica de 3 estados do
// Disparo Inicial — nunca sinalizado / sinalizado sem detalhe / já
// com detalhe narrativo completo
const acumuloFuncao = getPath(dados, "agravantes.acumulo_funcao");
const substituicaoFuncao = getPath(dados, "agravantes.substituicao_funcao");
const desvioFuncaoTexto = getPath(dados, "vinculo.desvio_funcao");

const sinalizadoPorBooleano = acumuloFuncao !== undefined || substituicaoFuncao !== undefined;
const jaTemDetalheNarrativo = !!desvioFuncaoTexto;

if (!sinalizadoPorBooleano && !jaTemDetalheNarrativo) {
  pendentesKeys.push("desvio_funcao");
} else if (sinalizadoPorBooleano && !jaTemDetalheNarrativo) {
  pendentesKeys.push("detalhe_substituicao");
}

for (const tipo of schemaDocumentos) {
  if (!tiposRecebidos.has(tipo)) {
    pendentesKeys.push(tipo);
  }
}

const nome = item.cliente_nome_completo || item.nome || "";

const listaPerguntasCompleta = pendentesKeys
  .map((chave, i) => `${i + 1}) ${perguntas[chave] || chave}`)
  .join("\n");

const LIMITE_PREVIEW = 4;
const previewKeys = pendentesKeys.slice(0, LIMITE_PREVIEW);
const restantes = pendentesKeys.length - previewKeys.length;

let previewTexto = previewKeys
  .map((chave, i) => `${i + 1}) ${perguntas[chave] || chave}`)
  .join(" ");

if (restantes > 0) {
  previewTexto += ` E mais ${restantes} ${restantes === 1 ? "item" : "itens"}, que retomamos na conversa.`;
}

const mensagemCompleta = `Olá, ${nome}! Passando para lembrar que ainda precisamos de algumas informações para dar andamento à sua ação:\n\n${previewTexto}\n\nAssim que puder, me envia por aqui. Qualquer dúvida, é só chamar!`;

const redisMemoryMessage = JSON.stringify({
  type: "ai",
  data: {
    content: mensagemCompleta,
    tool_calls: [],
    invalid_tool_calls: [],
    additional_kwargs: {},
    response_metadata: {}
  }
});

const body = {
  messaging_product: "whatsapp",
  to: String(item.telefone),
  type: "template",
  template: {
    name: "followup_entrevista_peticao",
    language: { code: "pt_BR" },
    components: [
      {
        type: "body",
        parameters: [
          { type: "text", text: nome },
          { type: "text", text: previewTexto },
        ],
      },
    ],
  },
};

return [{
  json: {
    id: item.id,
    telefone: item.telefone,
    nome,
    pendentes: pendentesKeys,
    lista_perguntas_completa: listaPerguntasCompleta,
    mensagem_completa: mensagemCompleta,
    redis_memory_message: redisMemoryMessage,
    resultado: body,
